// 兼容：HTTP 节点可能已将 JSON 数组拆分为多个 item，也可能保留为单个 item
// 先用 $input.all() 尝试获取所有 item
var items = $input.all();
var sources = [];

for (var i = 0; i < items.length; i++) {
  var raw = items[i].json;

  if (typeof raw === 'string') {
    // 字符串 → 解析 JSON
    var parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) {
      sources = sources.concat(parsed);
    } else {
      sources.push(parsed);
    }
  } else if (Array.isArray(raw)) {
    // 数组 → 扁平化合并
    sources = sources.concat(raw);
  } else if (raw && typeof raw === 'object') {
    // 对象 → 可能是单个源，或包装了 body/data
    if (raw.id && raw.url && raw.label) {
      sources.push(raw);
    } else if (Array.isArray(raw.body)) {
      sources = sources.concat(raw.body);
    } else if (Array.isArray(raw.data)) {
      sources = sources.concat(raw.data);
    } else {
      // 未知对象格式，尝试直接使用
      sources.push(raw);
    }
  }
}

if (sources.length === 0) {
  throw new Error('No sources. Items count: ' + items.length + ', sample: ' + JSON.stringify(items[0] ? items[0].json : null).substring(0, 300));
}

return sources.map(function(s) {
  return {
    json: {
      targetUrl: s.url,
      sourceLabel: s.label,
      sourceId: s.id,
      sourceType: s.type || 'webpage',
      contentSelector: s.contentSelector || null,
      runId: 'nx2-' + Date.now() + '-' + (s.id || '').substring(0, 6)
    }
  };
});

// 根据源类型构建抓取请求
var src = $input.first().json;

// RSS: 直接用 HTTP GET 抓取
if (src.sourceType === 'rss') {
  return {
    method: 'GET',
    url: src.targetUrl,
    _mode: 'rss',
    _sourceId: src.sourceId,
    _sourceLabel: src.sourceLabel,
    _run_id: src.runId
  };
}

// Webpage: 通过 browserless（仅传元数据，HTTP 节点自行组装 body）
return {
  _mode: 'webpage',
  _sourceId: src.sourceId,
  _sourceLabel: src.sourceLabel,
  _targetUrl: src.targetUrl,
  _contentSelector: src.contentSelector,
  _run_id: src.runId
};

// 组装 browserless /content 请求体
var item = $input.first().json;
return {
  url: item._targetUrl
};

// 清洗抓取结果：RSS XML → 拆分为多篇独立文章 | 网页 HTML → 去标签清洗
var scraped = String($input.first().json);
var meta = $('📦 构建抓取请求').first().json;

function stripTags(s) {
  return s
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&apos;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

// ── RSS 模式：解析 <item> 标签，每篇文章成为一个独立 item ──
if (meta._mode === 'rss') {
  var items = [];
  var re = /<item>([\s\S]*?)<\/item>/gi;
  var m;
  while ((m = re.exec(scraped)) !== null) {
    var xml = m[1];
    var t = xml.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
    var l = xml.match(/<link[^>]*>([\s\S]*?)<\/link>/i);
    var d = xml.match(/<description[^>]*>([\s\S]*?)<\/description>/i);
    var title = t ? stripTags(t[1]) : '';
    var link = l ? stripTags(l[1]) : '';
    var body = d ? stripTags(d[1]) : stripTags(xml);

    if (title || body) {
      items.push({
        json: {
          _owl_source_url: link || meta.url,
          _owl_raw_title: title,
          _owl_raw_body: body.substring(0, 8000),
          _run_id: meta._run_id + '-' + items.length,
          _sourceId: meta._sourceId,
          _sourceLabel: meta._sourceLabel
        }
      });
    }
    if (items.length >= 10) break;   // 每次最多取 10 篇
  }
  if (items.length > 0) return items;

  // RSS 格式异常（无 <item>），降级为单篇处理
  var ft = scraped.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
  return {
    _owl_source_url: 'rss://' + (meta._sourceLabel || '未知来源'),
    _owl_raw_title: ft ? stripTags(ft[1]) : (meta._sourceLabel || 'RSS'),
    _owl_raw_body: stripTags(scraped).substring(0, 8000),
    _run_id: meta._run_id,
    _sourceId: meta._sourceId,
    _sourceLabel: meta._sourceLabel
  };
}

// ── Webpage 模式：HTML 清洗 ──
var titleMatch = scraped.match(/<title[^>]*>([^<]+)<\/title>/i);
var title = titleMatch ? titleMatch[1].trim() : (meta._sourceLabel || '未知标题');
var body = stripTags(scraped);
if (meta._contentSelector && meta._mode === 'webpage') {
  var sel = meta._contentSelector;
  var pattern = new RegExp('<' + sel + '[^>]*>([\\s\\S]*?)<\\/' + sel + '>', 'i');
  var selMatch = scraped.match(pattern);
  if (selMatch) { body = stripTags(selMatch[1]); }
}

return {
  _owl_source_url: meta._targetUrl || meta.url,
  _owl_raw_title: title,
  _owl_raw_body: body.substring(0, 8000),
  _run_id: meta._run_id,
  _sourceId: meta._sourceId,
  _sourceLabel: meta._sourceLabel
};

// 构建 Newton Prompt + 计算内容哈希
var owl = $input.first().json;

// 简单哈希（替代 crypto 模块，沙箱兼容）
function simpleHash(s) {
  var h = 0;
  for (var i = 0; i < s.length; i++) {
    h = ((h << 5) - h + s.charCodeAt(i)) | 0;
  }
  return 'h' + Math.abs(h).toString(16);
}
var contentHash = simpleHash(owl._owl_raw_title + owl._owl_raw_body.substring(0, 500));

var systemPrompt = '你是AI-Newton学长，Nexus Hub首席学术主笔。\n\n身份：资深留学升学顾问，10年+ A-Level/AP/IB 辅导经验。经历过裱花内卷、ED被翠菊、全聚德后Waitlist逆袭。\n风格：真实感>权威感，过来人口吻，自然使用2-4个黑话（裱花/脆拒/全聚德/冲金/爆零/肝/摆烂/内耗）。\n\n输出格式铁律：\n1. 第一行输出 "# " 开头的 Markdown 标题（15-30字，概括全文核心观点，制造悬念/反常识/数据冲击）。\n2. 从第二行开始写正文，Markdown严谨排版（##小标题、|表格|、>引用、-列表），800-1200字。\n3. 文章最后一行必须输出 [BOARD: 板块slug]，从以下15个板块中选择最匹配的一个：sat-act(SAT/ACT)、ap-olympiad(AP与竞赛)、alevel-ib(A-Level/IB)、lang-exams(语言考试)、school-select(选校定位)、essay-writing(文书写作)、app-strategy(申请策略)、bg-boost(背景提升)、us-undergrad(美国本科)、uk-commonwealth(英联邦)、eu-asia(欧亚及其他)、visa-immigration(签证移民)、pre-departure(行前准备)、career-jobs(实习就业)、student-life(留学生活)。';

var userMessage = '根据以下资讯撰写一篇面向留学生的深度解析文章。\n\n【资讯来源】' + owl._owl_source_url + '\n【资讯原文标题】' + owl._owl_raw_title + '\n【资讯正文】' + owl._owl_raw_body + '\n\n【硬性要求】\n1. 第一行用 "# " 开头输出 Markdown 标题（15-30字，概括全文核心结论，标题党风格）\n2. 开头用场景/反问制造共鸣\n3. 深入分析2-3个维度\n4. 给出3-5条可操作建议\n5. 用表格总结关键数据\n6. 自然使用2-4个黑话词汇\n7. 保持过来人口吻';

return {
  model: 'deepseek-chat',
  temperature: 0.7,
  max_tokens: 4096,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ],
  _owl_source_url: owl._owl_source_url,
  _owl_raw_title: owl._owl_raw_title,
  _sourceId: owl._sourceId,
  _sourceLabel: owl._sourceLabel,
  _contentHash: contentHash,
  _run_id: owl._run_id
};

// 提取标题 + 判断 subreddit + 构建发布请求
var response = $input.first().json;
var prompt = $('🧠 Newton Prompt').first().json;
var article = (response.choices && response.choices[0] && response.choices[0].message && response.choices[0].message.content) || '';

// Extract board classification from LLM output: [BOARD: slug]
var boardMatch = article.match(/\[BOARD:\s*([a-z-]+)\]/i);
var subredditName = boardMatch ? boardMatch[1] : 'student-life';
// Remove the board marker from displayed content
article = article.replace(/\n?\[BOARD:\s*[a-z-]+\]\s*/i, '');

var lines = article.split('\n');
var title = '';

// Priority 1: Find markdown heading
for (var i = 0; i < lines.length; i++) {
  if (/^#{1,3}\s/.test(lines[i].trim())) {
    title = lines[i].replace(/^#{1,3}\s*/, '').trim();
    break;
  }
}

// Priority 2: Fallback to first meaningful line
if (!title || title.length < 5) {
  for (var j = 0; j < lines.length; j++) {
    var t = lines[j].trim();
    if (t && t.indexOf('```') !== 0 && t.indexOf('>') !== 0 && t.indexOf('|') !== 0 && t.indexOf('-') !== 0 && t.length > 5) {
      title = t.substring(0, 100);
      break;
    }
  }
}

if (!title) title = '无标题';
title = title.replace(/^[#*\s]+/, '').replace(/[#*\s]+$/, '').replace(/^(你的标题|标题)[：:\s]*/i, '').substring(0, 100);

return {
  secret_key: 'nexus-hub-test-secret-2026',
  title: title,
  content: article,
  subredditName: subredditName,
  authorRole: 'Newton',
  _sourceId: prompt._sourceId,
  _sourceLabel: prompt._sourceLabel,
  _contentHash: prompt._contentHash,
  _owl_raw_title: prompt._owl_raw_title
};

// 构建采集日志请求体 — 区分 success / deduplicated / failed
var publishResult = $input.first().json;
var midas = $('⚡ Midas 构建发布').first().json;

var status, postId;
if (publishResult.duplicate) {
  status = 'deduplicated';
  postId = publishResult.existingPostId || null;
} else if (publishResult.id) {
  status = 'success';
  postId = publishResult.id;
} else {
  status = 'failed';
  postId = null;
}

return {
  secret_key: 'nexus-hub-test-secret-2026',
  sourceId: midas._sourceId,
  status: status,
  title: midas._owl_raw_title || midas.title,
  contentHash: midas._contentHash,
  contentLength: (midas.content || '').length,
  postId: postId,
  _pipeline: 'Nexus Hub v2',
  _post_id: postId,
  _subreddit: publishResult.subredditName,
  _source_id: midas._sourceId,
  _timestamp: new Date().toISOString()
};

var logResult = $input.first().json;
var meta = $('📝 构建日志').first().json;

return {
  pipeline: meta._pipeline || 'Nexus Hub v2',
  status: meta._post_id ? 'published' : (meta.status || 'done'),
  post_id: meta._post_id || null,
  subreddit: meta._subreddit,
  source_id: meta._source_id,
  crawl_log_id: logResult.id || null,
  timestamp: meta._timestamp || new Date().toISOString()
};
